/* Banque de questions - HLT Fascicule I (Conducteur de train SNCB) - Avis 01/02/03 B-TO 2026 */
/* ch: 1=Structure des chemins de fer belges, 2=Connaissances du conducteur, 3=De la prise a la fin de service */
/* lvl: d=debutant, m=moyen, x=difficile | type: qcm=1 reponse, qrm=plusieurs reponses | correct = indices */

const QUESTIONS = [
/* ===================== DEBUTANT ===================== */
{id:1,ch:1,lvl:"d",type:"qcm",q:"Qui est le gestionnaire de l'infrastructure (GI) pour la quasi-totalite du reseau belge ?",opts:["Infrabel","La SNCB","Le SSICF","HR Rail"],correct:[0],expOk:"Infrabel est le GI charge de la gestion et de la maintenance de l'infrastructure ferroviaire.",expNo:"Le GI est Infrabel. La SNCB est une entreprise ferroviaire (EF), pas le gestionnaire d'infrastructure."},
{id:2,ch:1,lvl:"d",type:"qcm",q:"La SNCB est...",opts:["une entreprise ferroviaire (EF)","le gestionnaire d'infrastructure","une direction d'Infrabel","un poste de signalisation"],correct:[0],expOk:"La SNCB est une EF (aussi appelee utilisateur de l'infrastructure, UI), chargee du transport de voyageurs.",expNo:"La SNCB est une entreprise ferroviaire (EF/UI). Le gestionnaire d'infrastructure est Infrabel."},
{id:3,ch:1,lvl:"d",type:"qcm",q:"En combien d'Areas le reseau Infrabel est-il divise ?",opts:["5","3","4","13"],correct:[0],expOk:"Le reseau est divise en 5 Areas (NW, NO, CE, SE, SO), qui correspondent aux districts.",expNo:"Il y a 5 Areas (NW, NO, CE, SE, SO). 13 correspond au nombre de zones, pas d'Areas."},
{id:4,ch:1,lvl:"d",type:"qcm",q:"A quoi reconnait-on un agent du mouvement sur le terrain ?",opts:["Kepi bleu et gilet fluorescent au logo Infrabel","Brassard orange au logo Infrabel","Coiffe bleue au logo SNCB","Veste avec mentions Leader"],correct:[0],expOk:"L'agent du mouvement porte un kepi bleu et un gilet fluorescent au logo Infrabel.",expNo:"Le brassard orange caracterise le Leader Infrabel ; la coiffe bleue logo SNCB, le personnel d'accompagnement."},
{id:5,ch:1,lvl:"d",type:"qcm",q:"Le conducteur de manoeuvre est limite a quelle vitesse maximale ?",opts:["60 km/h","40 km/h","25 km/h","100 km/h"],correct:[0],expOk:"Le conducteur de manoeuvre est limite a 60 km/h et a un rayon d'action de 25 km autour de l'installation.",expNo:"La vitesse maximale est de 60 km/h. 25 km correspond au rayon d'action maximal, pas a la vitesse."},
{id:6,ch:1,lvl:"d",type:"qrm",q:"Lesquelles sont des directions de la SNCB ? (plusieurs reponses)",opts:["B-TO","B-CS","B-PT","I-O"],correct:[0,1,2],expOk:"B-TO, B-CS, B-PT (ainsi que B-TC et B-ST) sont des directions SNCB. I-O est une direction d'Infrabel.",expNo:"I-O (Operation) est une direction d'Infrabel, pas de la SNCB. Les directions SNCB sont B-TO, B-CS, B-PT, B-TC, B-ST."},
{id:7,ch:1,lvl:"d",type:"qcm",q:"Le Leader Infrabel est reconnaissable a...",opts:["son brassard orange orne du logo Infrabel","son kepi bleu","sa coiffe bleue SNCB","un gilet jaune"],correct:[0],expOk:"Le Leader Infrabel porte un brassard orange au logo Infrabel et fait fonction de SPOC (Single Point Of Contact).",expNo:"Le brassard orange au logo Infrabel identifie le Leader Infrabel."},
{id:8,ch:1,lvl:"d",type:"qcm",q:"Que signifie l'abreviation CT dans le HLT ?",opts:["Conducteur de train","Controleur de trafic","Coordination Traction","Central Team"],correct:[0],expOk:"CT designe le conducteur de train.",expNo:"Dans le HLT, CT = conducteur de train."},
{id:9,ch:1,lvl:"d",type:"qcm",q:"Combien de districts compte le reseau pour les depots de conducteurs ?",opts:["5","13","3","6"],correct:[0],expOk:"Il y a 5 districts (NO, NW, SO, SE, CE) regroupant 13 zones.",expNo:"5 districts ; les 13 correspondent aux zones geographiques."},
{id:10,ch:1,lvl:"d",type:"qcm",q:"La permanence conduite a notamment pour mission...",opts:["d'assurer la gestion en temps reel des conducteurs (ex. remplacement d'un malade)","la maintenance des catenaires","le marketing clients","l'entretien des gares"],correct:[0],expOk:"La permanence conduite gere en temps reel les conducteurs : remplacements, suivi des services non planifies.",expNo:"La gestion temps reel des conducteurs releve de la permanence conduite ; les catenaires relevent du repartiteur courant-traction."},
{id:11,ch:2,lvl:"d",type:"qcm",q:"Quelle est la duree de validite de la licence de conducteur ?",opts:["10 ans","3 ans","5 ans","1 an"],correct:[0],expOk:"La licence de conducteur est valable 10 ans (tant que les examens medicaux/psycho sont a jour).",expNo:"La licence vaut 10 ans. 3 ans correspond a l'attestation complementaire."},
{id:12,ch:2,lvl:"d",type:"qcm",q:"Quelle est la duree de validite de l'attestation complementaire ?",opts:["3 ans","10 ans","5 ans","2 ans"],correct:[0],expOk:"L'attestation complementaire, delivree par l'UI employeur, est valable 3 ans.",expNo:"L'attestation complementaire vaut 3 ans. 10 ans correspond a la licence."},
{id:13,ch:2,lvl:"d",type:"qcm",q:"A qui appartient la licence de conducteur ?",opts:["au titulaire (le conducteur)","a l'UI employeur","a Infrabel","au SSICF"],correct:[0],expOk:"La licence est la propriete de son titulaire. L'attestation complementaire, elle, reste propriete de l'UI.",expNo:"La licence appartient au titulaire ; c'est l'attestation complementaire qui reste la propriete de l'UI."},
{id:14,ch:2,lvl:"d",type:"qcm",q:"Tous les combien le conducteur passe-t-il des tests psychotechniques ?",opts:["tous les 10 ans","tous les ans","tous les 3 ans","tous les 5 ans"],correct:[0],expOk:"Les tests psychotechniques ont lieu tous les 10 ans.",expNo:"Tous les 10 ans pour les psychotechniques. La visite medicale est annuelle ; l'examen approfondi tous les 3 ans."},
{id:15,ch:2,lvl:"d",type:"qcm",q:"A quelle frequence le conducteur passe-t-il une visite medicale ?",opts:["chaque annee","tous les 3 ans","tous les 10 ans","tous les 6 mois"],correct:[0],expOk:"La visite medicale est annuelle. Tous les 3 ans (annuellement des 55 ans), elle est plus approfondie.",expNo:"La visite medicale est annuelle. L'examen plus approfondi a lieu tous les 3 ans (annuellement des 55 ans)."},
{id:16,ch:2,lvl:"d",type:"qcm",q:"La formation generale qui permet d'obtenir la licence dure...",opts:["18 jours","6 jours","30 jours","3 mois"],correct:[0],expOk:"La formation generale dure 18 jours et mene a la licence de conducteur.",expNo:"La formation generale dure 18 jours."},
{id:17,ch:2,lvl:"d",type:"qcm",q:"Que code la lettre F dans la rubrique connaissances linguistiques ?",opts:["connaissance suffisante du francais","connaissance du flamand","formation","fret"],correct:[0],expOk:"F = francais, N = neerlandais, E = anglais, D = allemand.",expNo:"F designe la connaissance suffisante du francais."},
{id:18,ch:2,lvl:"d",type:"qrm",q:"Le candidat-conducteur est recrute apres evaluation positive de... (plusieurs reponses)",opts:["un entretien d'embauche","une epreuve psychotechnique","une visite medicale","10 ans d'anciennete"],correct:[0,1,2],expOk:"Les trois conditions sont : entretien d'embauche, epreuve psychotechnique et visite medicale.",expNo:"Le recrutement repose sur l'entretien, l'epreuve psychotechnique et la visite medicale - pas sur l'anciennete."},
{id:19,ch:2,lvl:"d",type:"qcm",q:"Quel score minimal faut-il pour reussir l'evaluation de la connaissance de ligne ?",opts:["60 %","50 %","70 %","80 %"],correct:[0],expOk:"Il faut au moins 60 % des points et aucune faute grave contre la securite.",expNo:"Le seuil est de 60 % sans faute grave contre la securite."},
{id:20,ch:2,lvl:"d",type:"qcm",q:"La formation permanente est proposee...",opts:["chaque semestre","chaque mois","chaque annee","chaque semaine"],correct:[0],expOk:"Le conducteur est invite a une formation permanente chaque semestre.",expNo:"La formation permanente est semestrielle."},
{id:21,ch:3,lvl:"d",type:"qcm",q:"Comment s'appelle la tablette sur laquelle le conducteur dispose de ses prescriptions ?",opts:["eDrive","DISCO","SEMES","ELAN"],correct:[0],expOk:"Les prescriptions sont disponibles sur la tablette eDrive (eDrive-app).",expNo:"La tablette s'appelle eDrive. DISCO designe les ecrans du local de prise de service."},
{id:22,ch:3,lvl:"d",type:"qcm",q:"Que signifie HLP ?",opts:["Haut le pied","Halte ligne principale","Heure limite de prestation","Hors-ligne prioritaire"],correct:[0],expOk:"HLP = haut le pied : le conducteur est dans un vehicule sans en assurer la conduite.",expNo:"HLP = haut le pied."},
{id:23,ch:3,lvl:"d",type:"qcm",q:"Le rapport du conducteur au format digital se nomme...",opts:["M510e","M510","M510bis","M355"],correct:[0],expOk:"Le M510e est le rapport digital (via eDrive-app) ; le M510 est sa version papier.",expNo:"Le format digital est le M510e ; le M510 est le format papier."},
{id:24,ch:3,lvl:"d",type:"qcm",q:"Quel livre d'ordres contient les supplements au livret HLT ?",opts:["LO3","LO1","LO4","LO6"],correct:[0],expOk:"Le LO3 contient les supplements provisoires et definitifs au livret HLT.",expNo:"C'est le LO3. Le LO1 contient un lien vers SEMES 2.0 ; le LO4, les REX."},
{id:25,ch:3,lvl:"d",type:"qcm",q:"Pendant la conduite, le conducteur...",opts:["n'ecoute pas de musique","peut ecouter la radio a faible volume","peut utiliser son telephone personnel","peut regarder une video"],correct:[0],expOk:"Pendant la conduite, le conducteur n'ecoute pas de musique et n'utilise que les appareils fournis par l'employeur.",expNo:"La musique est interdite pendant la conduite, comme tout appareil non fourni par l'employeur."},
{id:26,ch:3,lvl:"d",type:"qcm",q:"Que contient l'application RID ?",opts:["les directives en cas d'incident avec des marchandises dangereuses","les fiches de ligne","les avis de securite ART","le calendrier des formations"],correct:[0],expOk:"La RID-app fournit les directives lors d'un incident avec wagons de marchandises dangereuses ; consultable sans reseau.",expNo:"La RID-app concerne les marchandises dangereuses."},
{id:27,ch:3,lvl:"d",type:"qcm",q:"Au-dela de quelle temperature exterieure des bouteilles d'eau refrigerees sont-elles mises a disposition ?",opts:["25 degres C","30 degres C","20 degres C","28 degres C"],correct:[0],expOk:"Des bouteilles d'eau refrigerees sont mises a disposition si la temperature exterieure depasse 25 degres.",expNo:"Le seuil est de 25 degres C."},
{id:28,ch:3,lvl:"d",type:"qcm",q:"En fin de service, ou le conducteur prend-il connaissance de sa prochaine prestation ?",opts:["via l'icone Prestation suivante dans l'Apercu de l'eDrive-app","par courrier au depot","aupres du chef de bord","sur le PSS"],correct:[0],expOk:"La prochaine prestation se consulte via l'icone Prestation suivante de l'eDrive-app.",expNo:"C'est via l'icone Prestation suivante de l'eDrive-app. Une info de la permanence conduite par telephone primerait toutefois."},
{id:29,ch:3,lvl:"d",type:"qcm",q:"En cas d'agression ou de vandalisme, le conducteur contacte...",opts:["le SOC (Security Operations Center)","le Helpdesk","l'Infodesk","la CCT"],correct:[0],expOk:"Le conducteur contacte le SOC ; si le SOC ne repond pas, il appelle le 112.",expNo:"En cas d'agression/vandalisme, on contacte le SOC (puis le 112 si pas de reponse)."},
{id:30,ch:3,lvl:"d",type:"qcm",q:"Le Memento doit etre consulte...",opts:["uniquement a l'arret lors d'incidents","en roulant","avant chaque depart","une fois par semaine"],correct:[0],expOk:"Le Memento est concu pour etre consulte uniquement a l'arret lors d'incidents ; il ne remplace pas le HLT.",expNo:"Le Memento se consulte uniquement a l'arret, jamais en roulant. Il ne remplace pas le HLT."},
{id:31,ch:2,lvl:"d",type:"qcm",q:"En cas de PERTE de la licence ou de l'attestation, le conducteur informe son encadrement en redigeant...",opts:["un D233","un P1103","un M355","un D24"],correct:[0],expOk:"Une perte se signale via un D233 ; un vol, en transmettant le proces-verbal de police.",expNo:"La perte se signale par un D233. Le P1103 concerne le port de lunettes/lentilles/appareil auditif."},
{id:32,ch:1,lvl:"d",type:"qcm",q:"Quel organe national intervient en appui des postes de signalisation pour la coordination du trafic en cas de perturbations ?",opts:["le Central Dispatch","le RIOC","la CCT","le SOC"],correct:[0],expOk:"Le Central Dispatch (CD, OCT, VCO) appuie les postes de signalisation pour coordonner le trafic en cas de perturbations.",expNo:"C'est le Central Dispatch. Le RIOC s'occupe des irregularites a l'infrastructure."},
{id:33,ch:3,lvl:"d",type:"qcm",q:"Quel document independant du M510 sert pour les avis urgents et conditions meteo exceptionnelles ?",opts:["le M510bis","le M510e","le TC612","le D24"],correct:[0],expOk:"Le M510bis est un document independant du M510, a completer pour les avis urgents et conditions meteo exceptionnelles.",expNo:"Il s'agit du M510bis."},
{id:34,ch:1,lvl:"d",type:"qcm",q:"Le personnel d'accompagnement (accompagnateur de train) est reconnaissable a...",opts:["son kepi ou sa coiffe bleue ornes du logo SNCB","son brassard orange","son gilet orange fluo","son kepi rouge"],correct:[0],expOk:"L'accompagnateur de train porte un kepi ou une coiffe bleue au logo SNCB.",expNo:"Le logo SNCB sur kepi/coiffe bleue identifie l'accompagnateur ; le brassard orange, le Leader Infrabel."},
{id:35,ch:2,lvl:"d",type:"qcm",q:"Quelle categorie de conduite correspond au transport de personnes ?",opts:["B1","A1","A4","B2"],correct:[0],expOk:"B1 = transport de personnes. A1/A4 = locomotives de manoeuvre, B2 = marchandises.",expNo:"B1 correspond au transport de personnes."},
/* ===================== MOYEN ===================== */
{id:36,ch:1,lvl:"m",type:"qrm",q:"Quels roles relevent de la direction I-O d'Infrabel ? (plusieurs reponses)",opts:["la regulation du trafic ferroviaire","l'attribution des sillons imprevus en temps reel","la gestion des catenaires et de l'alimentation electrique","l'attribution des sillons prevus"],correct:[0,1,2],expOk:"I-O gere la regulation du trafic, les sillons imprevus (realtime), les catenaires/alimentation et la maintenance.",expNo:"L'attribution des sillons PREVUS releve d'I-CBE, pas d'I-O. I-O gere les sillons IMPREVUS en temps reel."},
{id:37,ch:1,lvl:"m",type:"qcm",q:"Au Central Dispatch, qui est responsable de l'attribution des sillons en temps reel ?",opts:["le Train Path Manager (TPM)","le Traffic Officer (TO)","le Freight Supervisor (FSv)","le Realtime Analyst (RTA)"],correct:[0],expOk:"Le Train Path Manager (TPM) attribue les sillons en temps reel.",expNo:"C'est le TPM. Le TO gere le CD en temps reel ; le FSv suit le trafic marchandises ; le RTA analyse les retards."},
{id:38,ch:1,lvl:"m",type:"qcm",q:"Dans un poste de signalisation, qui coordonne les Safety Controllers ?",opts:["le Safety Supervisor","le Traffic Supervisor","le Traffic Officer","le Traffic Controller"],correct:[0],expOk:"Le Safety Supervisor coordonne les Safety Controllers ; le Traffic Supervisor coordonne les Traffic Controllers.",expNo:"Le Safety Supervisor coordonne les Safety Controllers. Le Traffic Supervisor coordonne les Traffic Controllers."},
{id:39,ch:1,lvl:"m",type:"qrm",q:"Le repartiteur courant-traction peut interrompre l'alimentation des catenaires a la demande... (plusieurs reponses)",opts:["du Safety Controller","d'un conducteur de train","de sa propre initiative","d'un accompagnateur de train"],correct:[0,1,2],expOk:"Il peut couper l'alimentation a la demande du Safety Controller, d'un conducteur, ou de sa propre initiative.",expNo:"L'accompagnateur de train ne figure pas parmi les demandeurs : ce sont le Safety Controller, le conducteur, ou sa propre initiative."},
{id:40,ch:1,lvl:"m",type:"qcm",q:"Quelle entite assiste le conducteur victime d'un evenement choquant ou traumatisant (ex. SPAD) ?",opts:["l'API (assistant post incident)","le FI (first investigator)","le SOC","le Leader SNCB"],correct:[0],expOk:"L'API assiste le conducteur victime d'un evenement choquant/traumatisant. Le FI realise les premieres constatations.",expNo:"C'est l'API qui assiste le conducteur. Le FI intervient pour les constatations (SPAD, derive, etc.)."},
{id:41,ch:1,lvl:"m",type:"qcm",q:"Que signifie SPAD ?",opts:["Signal Passed At Danger (depassement de signal)","Safety Protection And Defense","Service Permanent d'Assistance au Depot","Signal Position A Distance"],correct:[0],expOk:"SPAD = Signal Passed At Danger, soit un depassement de signal.",expNo:"SPAD = Signal Passed At Danger (depassement de signal)."},
{id:42,ch:1,lvl:"m",type:"qcm",q:"Le gestionnaire local de l'installation SNCB au niveau des ateliers de traction appartient a...",opts:["B-TC","B-TO","B-PT","B-CS"],correct:[0],expOk:"Aux ateliers de traction, il appartient a B-TC (ex. agent du service de cour). Grands faisceaux -> B-TO ; petits faisceaux/quais -> B-PT.",expNo:"Aux ateliers de traction, c'est B-TC. B-TO gere les grands faisceaux ; B-PT les petits faisceaux et quais."},
{id:43,ch:1,lvl:"m",type:"qcm",q:"Le service d'assistance technique qui NE depend PAS de la direction B-TC s'appelle...",opts:["la Hotline","le Helpdesk","l'Infodesk","la CCT"],correct:[0],expOk:"Le Helpdesk depend de B-TC ; la Hotline n'en depend pas.",expNo:"La Hotline ne depend pas de B-TC ; le Helpdesk en depend."},
{id:44,ch:2,lvl:"m",type:"qrm",q:"Un examen des connaissances professionnelles specifiques est requis lorsque... (plusieurs reponses)",opts:["le bilan periodique n'est pas satisfaisant","la conduite a ete interrompue plus de 6 mois","le critere de monitoring theorique n'est pas atteint","le conducteur change de depot"],correct:[0,1,2],expOk:"Bilan non satisfaisant, interruption > 6 mois, critere monitoring non atteint, ou decision de l'encadrement (faute grave, lacunes).",expNo:"Un changement de depot n'impose pas cet examen ; les motifs sont le bilan, l'interruption > 6 mois, le monitoring, ou une decision de l'encadrement."},
{id:45,ch:2,lvl:"m",type:"qcm",q:"Depuis 2016, quel niveau de connaissances linguistiques est requis pour les conducteurs ?",opts:["B1","A2","B2","C1"],correct:[0],expOk:"Depuis le 01/01/2016, le niveau requis est B1.",expNo:"Le niveau requis est B1."},
{id:46,ch:2,lvl:"m",type:"qcm",q:"Le conducteur qui n'a plus parcouru une ligne depuis combien de temps doit le notifier a son M510e ?",opts:["10 mois","12 mois","6 mois","3 mois"],correct:[0],expOk:"Au-dela de 10 mois sans parcours, le conducteur le notifie a son M510e. Un parcours dans les 12 mois prolonge la connaissance.",expNo:"Le seuil de notification est de 10 mois. Les 12 mois concernent le delai pour prolonger la connaissance par un parcours."},
{id:47,ch:2,lvl:"m",type:"qcm",q:"Qui interrompt les taches critiques de securite en retirant/suspendant la LICENCE ?",opts:["le SSICF","l'EF qui a emis l'attestation","le GI","le FI"],correct:[0],expOk:"Le SSICF retire/suspend la licence. L'EF emettrice retire/suspend l'attestation complementaire.",expNo:"La licence est retiree par le SSICF ; l'attestation complementaire l'est par l'EF emettrice."},
{id:48,ch:2,lvl:"m",type:"qcm",q:"Que doit faire le conducteur s'il doit desormais porter des lunettes pendant la validite de sa licence ?",opts:["rediger un P1103","rediger un D233","rediger un M355","ne rien faire"],correct:[0],expOk:"Il redige un P1103 pour informer son encadrement (de meme s'il n'est plus tenu d'en porter).",expNo:"Le port de lunettes/lentilles/appareil auditif se signale par un P1103. Le D233 concerne la perte d'un document."},
{id:49,ch:2,lvl:"m",type:"qcm",q:"La categorie de conduite A1 correspond a...",opts:["locomotives de manoeuvre","autres locomotives de manoeuvre","transport de personnes","transport de marchandises"],correct:[0],expOk:"A1 = locomotives de manoeuvre ; A4 = autres locomotives de manoeuvre ; B1 = personnes ; B2 = marchandises.",expNo:"A1 = locomotives de manoeuvre. B1 = personnes, B2 = marchandises."},
{id:50,ch:2,lvl:"m",type:"qrm",q:"Quelles entites peuvent controler la licence et l'attestation ? (plusieurs reponses)",opts:["le personnel du GI habilite","le SSICF","les forces de police","l'accompagnateur de train"],correct:[0,1,2],expOk:"GI habilite, SSICF, enqueteur de l'organisme d'enquete, forces de police, et l'encadrement du conducteur.",expNo:"L'accompagnateur de train ne controle pas la licence. Le controle revient a l'encadrement, au GI habilite, au SSICF, a l'enqueteur et a la police."},
{id:51,ch:2,lvl:"m",type:"qcm",q:"Quelle formation materiel traite de la protection de l'engin stationne contre le gel et la neige ?",opts:["la formation Protection du materiel roulant","la formation complete","la formation fondamentale","la formation permanente"],correct:[0],expOk:"La formation Protection du materiel roulant couvre la protection de l'engin stationne. La formation complete couvre conduite, fonctionnement et depannage.",expNo:"C'est la formation Protection du materiel roulant. La formation complete couvre la conduite et le depannage."},
{id:52,ch:2,lvl:"m",type:"qcm",q:"Dans une serie, a quel jour correspond la colonne R1 ?",opts:["lundi","dimanche","le premier jour de service","un jour de repos"],correct:[0],expOk:"R1 = lundi et R7 = dimanche dans la grille de serie.",expNo:"R1 = lundi (R7 = dimanche)."},
{id:53,ch:2,lvl:"m",type:"qcm",q:"Le bilan periodique est un entretien d'une duree maximale de...",opts:["60 minutes","30 minutes","90 minutes","120 minutes"],correct:[0],expOk:"L'entretien de bilan periodique dure au maximum 60 minutes.",expNo:"La duree maximale est de 60 minutes."},
{id:54,ch:3,lvl:"m",type:"qcm",q:"Quel livre d'ordres contient les communications B-TO relatives aux REX ?",opts:["le LO4","le LO2","le LO5","le LO6"],correct:[0],expOk:"Le LO4 contient les rappels HLT et les communications B-TO (REX, evolutions des prescriptions).",expNo:"Les REX sont au LO4. Le LO2 concerne l'infrastructure ; le LO5/LO6, les avis administratifs."},
{id:55,ch:3,lvl:"m",type:"qcm",q:"Lequel de ces avis de securite impose obligatoirement de consulter le schema ?",opts:["l'ARQ (raccourcissement de quai)","l'ART","l'ACPA","le REX"],correct:[0],expOk:"Pour un ARQ, le conducteur doit obligatoirement consulter le schema.",expNo:"C'est l'ARQ qui impose la consultation du schema. ART = reduction de vitesse, ACPA = pantographes abaisses."},
{id:56,ch:3,lvl:"m",type:"qcm",q:"Quelle difference majeure existe entre eSEMES et SEMES 2.0 ?",opts:["eSEMES est integre a l'eDrive-app, pas SEMES 2.0","SEMES 2.0 est integre a l'eDrive-app, pas eSEMES","les deux sont sur papier","aucune difference"],correct:[0],expOk:"eSEMES est integre dans l'eDrive-app ; SEMES 2.0 ne l'est pas (acces via lien LO1/INF ou Driver-tools-app).",expNo:"C'est eSEMES qui est integre a l'eDrive-app ; SEMES 2.0 ne l'est pas."},
{id:57,ch:3,lvl:"m",type:"qcm",q:"En cas de derangement de l'appareil eDrive pendant le service, quel appareil sert de remplacement ?",opts:["le GSM de service","le telephone personnel","un ecran DISCO","la RID-app"],correct:[0],expOk:"Le GSM de service sert de systeme de remplacement, en respectant les memes prescriptions.",expNo:"C'est le GSM de service. L'appareil personnel n'est jamais autorise."},
{id:58,ch:3,lvl:"m",type:"qcm",q:"Le franchissement des signaux permissifs se note dans quelle rubrique du M510 ?",opts:["rubrique 2","rubrique 1","rubrique 3","rubrique 5"],correct:[0],expOk:"Rubrique 2 = franchissement des signaux permissifs. Rubrique 1 = incidents/retards, 3 = annexes, 5 = presence de personnes en cabine.",expNo:"C'est la rubrique 2. La rubrique 1 concerne les incidents/retards/irregularites."},
{id:59,ch:3,lvl:"m",type:"qcm",q:"A quoi correspond le classement 2XX des fiches de deviation ?",opts:["axe Bruxelles - Pays-Bas (Prorail)","Bruxelles Nord","Dorsale Nord","axe Bruxelles - Allemagne"],correct:[0],expOk:"2XX = axe Bruxelles-Pays-Bas (Prorail). 1XX = Bruxelles Nord, 3XX = Dorsale Nord, 4XX = Bruxelles-Allemagne.",expNo:"2XX correspond a l'axe Bruxelles-Pays-Bas (Prorail)."},
{id:60,ch:3,lvl:"m",type:"qcm",q:"Qui le conducteur contacte-t-il pour le remplacement d'un appareil eDrive derange ?",opts:["le Helpdesk Mobile Devices","la permanence conduite","l'Infodesk","la CCT"],correct:[0],expOk:"Le Helpdesk Mobile Devices donne les directives et indique le Smartlocker contenant les appareils de remplacement.",expNo:"C'est le Helpdesk Mobile Devices qui gere le remplacement (Smartlocker)."},
{id:61,ch:3,lvl:"m",type:"qrm",q:"Quels titulaires de permis peuvent acceder a la cabine de conduite ? (plusieurs reponses)",opts:["TR-X01 (maitrise instruction-traction)","TR-X02 (DMR)","TR-X03 (Securail)","TR-X07"],correct:[0,1,2],expOk:"TR-X01/X02 (permis permanents) et TR-X03/X04 (permis temporaires) autorisent l'acces. TR-X07 est le code de reconnaissance comme formateur, pas un permis d'acces.",expNo:"TR-X07 n'est pas un permis d'acces cabine mais la reconnaissance comme formateur du centre SNCB. Les permis d'acces sont TR-X01 a X04."},
{id:62,ch:3,lvl:"m",type:"qcm",q:"En cas de perturbation importante, le conducteur en HLP se presente d'office...",opts:["au gestionnaire local de l'installation SNCB","au Leader Infrabel","a la CCT","au SOC"],correct:[0],expOk:"En perturbation importante, le conducteur HLP (ou reserve/stand-by sans operation dans la demi-heure) se presente au gestionnaire local de l'installation SNCB.",expNo:"Il se presente au gestionnaire local de l'installation SNCB."},
{id:63,ch:1,lvl:"m",type:"qcm",q:"Quelle direction d'Infrabel est responsable de l'attribution des sillons prevus ?",opts:["I-CBE","I-O","B-TO","RIOC"],correct:[0],expOk:"I-CBE (Customer & Business Excellence) attribue les sillons prevus ; I-O attribue les sillons imprevus en temps reel.",expNo:"Les sillons prevus relevent d'I-CBE ; les imprevus (realtime) d'I-O."},
{id:64,ch:1,lvl:"m",type:"qcm",q:"Avec quel organe le Central Dispatch est-il heberge conjointement a Bruxelles ?",opts:["le RIOC (Rail Infrastructure Operation Center)","le RCC","le SOC","le Helpdesk"],correct:[0],expOk:"Le CD est heberge a Bruxelles avec le RIOC, responsable de l'enregistrement des irregularites a l'infrastructure.",expNo:"Le CD est heberge avec le RIOC. Le RCC heberge la CCT cote SNCB."},
{id:65,ch:2,lvl:"m",type:"qcm",q:"Pour assurer un train de voyageurs commercial, un conducteur de manoeuvre doit...",opts:["etre accompagne d'un conducteur de train B1 connaissant suffisamment sa langue","obtenir l'accord du SSICF","passer un examen linguistique","rien, c'est interdit en toutes circonstances"],correct:[0],expOk:"Il peut evacuer un train de voyageurs commercial s'il est accompagne d'un conducteur de train B1 maitrisant suffisamment sa langue, sans depasser 60 km/h, et pilote s'il n'a pas la connaissance de ligne.",expNo:"Il le peut uniquement accompagne d'un conducteur de train B1, a 60 km/h max, et pilote si pas de connaissance de ligne."},
{id:66,ch:2,lvl:"m",type:"qcm",q:"Lors de l'annee de renouvellement, quand l'examen des connaissances linguistiques doit-il avoir lieu ?",opts:["au plus tot 3 mois avant la fin de validite et avant l'entretien du bilan","le jour de l'examen final","6 mois apres le renouvellement","apres l'entretien du bilan"],correct:[0],expOk:"Lors de l'annee de renouvellement, l'examen linguistique se tient au plus tot 3 mois avant la fin de validite et avant l'entretien du bilan.",expNo:"C'est au plus tot 3 mois avant la fin de validite et AVANT l'entretien du bilan."},
{id:67,ch:3,lvl:"m",type:"qcm",q:"Que doit faire le conducteur si les publications SEMES ne sont pas consultables via eSEMES ?",opts:["les consulter via SEMES 2.0 et les telecharger, puis contacter la permanence conduite si impossible","poursuivre sans les consulter","attendre la fin de service","contacter le SOC"],correct:[0],expOk:"Il prend connaissance des publications via SEMES 2.0 et les telecharge ; a defaut, il contacte la permanence conduite et suit les directives.",expNo:"Il bascule sur SEMES 2.0 (telechargement) et, a defaut, contacte la permanence conduite - il ne poursuit jamais sans en avoir pris connaissance."},
{id:68,ch:3,lvl:"m",type:"qcm",q:"Lors d'une audition de police, l'adresse que le conducteur doit fournir est...",opts:["celle de l'employeur (rubrique 1 de l'attestation complementaire)","son adresse personnelle","celle du depot","celle d'Infrabel"],correct:[0],expOk:"Pour preserver sa confidentialite, le conducteur fournit l'adresse de l'employeur, reprise a la rubrique 1 de l'attestation complementaire.",expNo:"Il fournit l'adresse de l'employeur (rubrique 1 de l'attestation), pas son adresse personnelle."},
{id:69,ch:3,lvl:"m",type:"qcm",q:"D'un point de vue STI, comment le livret HLT est-il appele ?",opts:["Livret de procedures","Livret de ligne","Livret de bord","Livret de securite"],correct:[0],expOk:"D'un point de vue STI, le HLT est le Livret de procedures. SEMES 2.0 et les fiches de ligne forment le Livret de ligne.",expNo:"Le HLT = Livret de procedures. Le Livret de ligne designe SEMES 2.0 et les fiches de ligne."},
{id:70,ch:3,lvl:"m",type:"qcm",q:"Le conducteur HLP qui prend place dans un compartiment voyageur doit...",opts:["informer le personnel de bord de sa presence, de preference avant le depart","s'installer obligatoirement en cabine","rester debout","presenter son rapport M510 aux voyageurs"],correct:[0],expOk:"Il informe le personnel de bord (qui peut demander un document d'identite) et cede la priorite d'une place assise a un voyageur muni d'un titre.",expNo:"Il doit informer le personnel de bord de sa presence, de preference avant le depart."},
/* ===================== DIFFICILE ===================== */
{id:71,ch:1,lvl:"x",type:"qcm",q:"Au Central Dispatch, qui traite les dossiers de retards ?",opts:["le Real Time Quality Officer (RT QO)","le Realtime Analyst (RTA)","l'Information Provider (IP)","le Central Dispatcher (CDr)"],correct:[0],expOk:"Le RT QO traite les dossiers de retards. Le RTA analyse les retards en temps reel ; l'IP diffuse les infos ; le CDr gere les incidents majeurs.",expNo:"C'est le RT QO. Attention a ne pas le confondre avec le RTA (analyse en temps reel) ou le CDr (incidents majeurs)."},
{id:72,ch:1,lvl:"x",type:"qrm",q:"Quelles zones appartiennent au district SE ? (plusieurs reponses)",opts:["Arlon","Liege","Namur","Mons"],correct:[0,1,2],expOk:"Le district SE regroupe Arlon, Liege et Namur. Mons (avec Charleroi) appartient au district SO.",expNo:"Mons releve du district SO (avec Charleroi). Le SE comprend Arlon, Liege et Namur."},
{id:73,ch:1,lvl:"x",type:"qrm",q:"Le FI (first investigator) intervient notamment lors... (plusieurs reponses)",opts:["d'un SPAD","du non-respect d'une vitesse signalisee","du deplacement intempestif d'un engin moteur (derive)","d'une visite medicale d'inaptitude"],correct:[0,1,2],expOk:"Le FI intervient lors d'un SPAD, d'une circulation anormale, du non-respect d'une vitesse signalisee et d'une derive.",expNo:"L'inaptitude medicale ne concerne pas le FI. Le FI intervient pour SPAD, circulation anormale, non-respect de vitesse, derive."},
{id:74,ch:1,lvl:"x",type:"qrm",q:"Pour faire partie du groupe instruction-traction, un agent doit notamment... (plusieurs reponses)",opts:["exercer une des fonctions d'encadrement listees","posseder au minimum le grade de sous-chef de secteur technique instruction-traction (faisant fonctions)","etre reconnu formateur du centre de formation SNCB (TR-X07)","avoir 10 ans d'anciennete"],correct:[0,1,2],expOk:"Les trois conditions cumulatives : exercer une fonction listee, avoir au moins le grade de sous-chef de secteur technique instruction-traction, et etre reconnu formateur (TR-X07).",expNo:"L'anciennete n'est pas un critere ; ce sont la fonction, le grade minimal et la reconnaissance TR-X07."},
{id:75,ch:1,lvl:"x",type:"qcm",q:"La gestion en temps reel de l'ICE3 est assuree par...",opts:["le Transportleitung de Duisbourg","B-TO.1","la CCT","le Central Dispatch"],correct:[0],expOk:"Selon la nature du materiel, la gestion temps reel peut etre confiee a des tiers : le Transportleitung de Duisbourg gere l'ICE3.",expNo:"L'ICE3 est gere en temps reel par le Transportleitung de Duisbourg (un tiers), pas par B-TO.1."},
{id:76,ch:1,lvl:"x",type:"qcm",q:"La CCT (Coordination Centrale Traction) est hebergee au sein du...",opts:["RCC (Realtime Coordination Center)","RIOC","Central Dispatch","SOC"],correct:[0],expOk:"La CCT est hebergee au RCC, avec le Helpdesk, la gestion du MR de SNCB Transport et les RTS-RCC.",expNo:"La CCT est au RCC. Le RIOC accompagne le Central Dispatch cote infrastructure."},
{id:77,ch:2,lvl:"x",type:"qcm",q:"Quelle information additionnelle (rubrique 4) certifie la conduite sur lignes a reperes d'arret en ETCS niveau 2 ?",opts:["Connaissance ETCS 2 REP","Connaissance ETCS 2 LAT","Connaissance ETCS 1 REP","Connaissance TVM"],correct:[0],expOk:"ETCS 2 REP certifie l'ETCS niveau 2 sur les lignes a reperes d'arret. LAT = signalisation laterale.",expNo:"REP = reperes d'arret, LAT = signalisation laterale. ETCS 2 REP est la bonne combinaison."},
{id:78,ch:2,lvl:"x",type:"qcm",q:"Pour maintenir la connaissance d'un type d'engin reste plus de 10 mois sans conduite, le bureau du tableau de service organise...",opts:["une preparation complete et un parcours dans un delai de 2 mois","une nouvelle formation complete","un examen theorique sous 6 mois","rien"],correct:[0],expOk:"Si la connaissance doit etre maintenue, une preparation complete et un parcours avec cet engin sont organises dans un delai de 2 mois.",expNo:"Le delai est de 2 mois pour une preparation complete et un parcours ; a defaut, l'attestation est adaptee."},
{id:79,ch:2,lvl:"x",type:"qcm",q:"Dans le cas d'un pilotage pour defaut de connaissance de ligne (art. 6.1.2), qui reste responsable du freinage du convoi ?",opts:["le conducteur pilote","le pilote","le GI","le Safety Controller"],correct:[0],expOk:"Quand le motif est le defaut de connaissance de ligne, le conducteur pilote indique la vitesse max et reste responsable du freinage ; le pilote gere signalisation et circulation.",expNo:"Pour un pilotage connaissance de ligne, le conducteur pilote reste responsable du freinage ; le pilote couvre signalisation/circulation."},
{id:80,ch:2,lvl:"x",type:"qrm",q:"Quels elements figurent au VERSO de la licence de conducteur ? (plusieurs reponses)",opts:["la langue maternelle (rubrique 9a.1)","des particularites d'ordre medical (rubrique 9b)","l'adresse du titulaire, facultative (rubrique 8)","le numero de licence en rubrique 5"],correct:[0,1,2],expOk:"Le verso reprend l'adresse (8, facultative), la langue maternelle (9a.1), le n de licence (9a.2) et les particularites medicales (9b). La rubrique 5 est au recto.",expNo:"La rubrique 5 (n de licence) figure au RECTO. Le verso contient les rubriques 8 et 9."},
{id:81,ch:2,lvl:"x",type:"qcm",q:"Sur le verso de la licence, que signifie la case 2 des particularites medicales (9b) ?",opts:["le port d'un appareil auditif","le port de lunettes ou lentilles","une restriction de conduite de jour","une dispense medicale"],correct:[0],expOk:"Case 1 = lunettes/lentilles ; case 2 = appareil auditif.",expNo:"La case 2 = appareil auditif ; la case 1 = lunettes ou lentilles."},
{id:82,ch:2,lvl:"x",type:"qcm",q:"Lors de l'etude de ligne, la carte SPAD-Hotspots est consultee via quelle icone de l'eDrive-app ?",opts:["l'icone INF","l'icone HLT","l'icone U","l'icone LO1"],correct:[0],expOk:"La carte SPAD-Hotspots est disponible sur l'eDrive-app via l'icone INF, si un signal d'arret y est reference.",expNo:"C'est l'icone INF (infrastructure). L'icone U concerne les avis urgents."},
{id:83,ch:2,lvl:"x",type:"qcm",q:"Quelle est la duree approximative de la partie reglementation organisee sur simulateur lors de l'examen des connaissances professionnelles specifiques ?",opts:["environ 1 heure","environ 30 minutes","environ 2 heures","environ 90 minutes"],correct:[0],expOk:"A la demande du conducteur, la partie reglementation peut se faire sur simulateur, pour une duree d'environ 1 heure.",expNo:"La duree est d'environ 1 heure."},
{id:84,ch:3,lvl:"x",type:"qcm",q:"Dans le code locomotive, que signifie la lettre U ?",opts:["HL en unite multiple (un seul conducteur)","HL d'allege","HL comme vehicule","deux HL chacune desservie par un conducteur"],correct:[0],expOk:"U = HL en unite multiple avec un seul conducteur (chiffre 4). D = deux HL, chacune avec son conducteur.",expNo:"U = unite multiple, un seul conducteur. D correspond a deux HL avec chacune un conducteur."},
{id:85,ch:3,lvl:"x",type:"qcm",q:"Sur la fiche de prestation, que signifie l'abreviation VK.PC ?",opts:["preparation complete d'engin(s) moteur(s)","preparation reduite","prise en charge INMAIN","passage au carwash"],correct:[0],expOk:"VK.PC = preparation complete (ou preparation courante - essais journaliers pour les TGV autres qu'ICE). BK.PR = preparation reduite.",expNo:"VK.PC = preparation complete. BK.PR designe la preparation reduite."},
{id:86,ch:3,lvl:"x",type:"qcm",q:"Que signifie INMAIN sur la fiche de prestation ?",opts:["la mise en maintien de service d'un engin moteur","la prise en charge d'un engin en maintien de service","une preparation reduite","un mouvement de manoeuvre"],correct:[0],expOk:"INMAIN = mise en maintien de service d'un engin moteur. IDREM = prise en charge d'un engin deja mis en INMAIN.",expNo:"INMAIN = mise en maintien de service. La prise en charge d'un tel engin est l'IDREM."},
{id:87,ch:3,lvl:"x",type:"qcm",q:"Le symbole < sur la fiche de prestation/service indique...",opts:["un arret de service qui doit toujours etre respecte","un arret respecte seulement si le signal de couverture l'impose","une vitesse conseillee","l'absence de vitesse conseillee"],correct:[0],expOk:"< = arret de service toujours a respecter ; > = arret a respecter seulement si le signal de couverture impose l'arret.",expNo:"< impose toujours l'arret ; c'est > qui depend du signal de couverture."},
{id:88,ch:3,lvl:"x",type:"qcm",q:"A quelle serie de numeros correspondent les trains Eurostar Londres - Bruxelles - Amsterdam ?",opts:["9100-9199","9800-9899","9300-9399","9500-9599"],correct:[0],expOk:"9100-9199 = Eurostar Londres-Bruxelles-Amsterdam. 9800-9899 = TGV ; 9300-9399 = Eurostar Paris-Bruxelles-Amsterdam.",expNo:"C'est 9100-9199. 9800-9899 designe les TGV."},
{id:89,ch:3,lvl:"x",type:"qrm",q:"Quels formulaires le conducteur emporte-t-il a 5 exemplaires a la prise de service ? (plusieurs reponses)",opts:["IE.1 a IE.9","IN.31 a IN.34","E360","M355"],correct:[0,1,2],expOk:"5 exemplaires de IE.1-IE.9, IN.21/22/23 et IN.31-34, E360, TC286 MOBI, TC612, TC431.1, M510, M510bis. Le M355 n'en fait pas partie.",expNo:"Le M355 est la fiche suiveuse du candidat, pas un formulaire emporte a 5 exemplaires. Les bons sont les IE, IN, E360, TC..., M510/M510bis."},
{id:90,ch:3,lvl:"x",type:"qcm",q:"Pour une locomotive electrique, dans le numero de service, la lettre B indique...",opts:["une bitension","une monotension","une polytension","un diagramme special"],correct:[0],expOk:"A = monotension, B = bitension, C = polytension, D et E = diagrammes speciaux.",expNo:"B = bitension. A = monotension, C = polytension."},
{id:91,ch:3,lvl:"x",type:"qcm",q:"Les appareils multimedia des personnes en cabine doivent etre en mode silencieux, a l'exception de ceux encodes dans...",opts:["la base de donnees ALASCA","la base ATLAS","la base ALACRA","la RID-app"],correct:[0],expOk:"Seuls les appareils encodes dans la base ALASCA echappent a l'obligation de mode silencieux en cabine.",expNo:"L'exception concerne la base de donnees ALASCA."},
{id:92,ch:1,lvl:"x",type:"qcm",q:"Quel grade fonctionnel est charge de l'organisation generale du poste de signalisation ?",opts:["le Traffic Officer","le Traffic Supervisor","le Safety Supervisor","le Traffic Controller"],correct:[0],expOk:"Dans un poste de signalisation, le Traffic Officer est charge de l'organisation generale.",expNo:"C'est le Traffic Officer. Le Traffic Supervisor coordonne les Traffic Controllers."},
{id:93,ch:1,lvl:"x",type:"qcm",q:"Quel service de la SNCB est en charge des prescriptions de conduite relatives au freinage des trains ?",opts:["B-TC.4","B-TO.4","B-PT.4","B-CS.1"],correct:[0],expOk:"B-TC.4 est en charge des etudes techniques du materiel roulant et des prescriptions de conduite relatives au freinage.",expNo:"Le freinage releve de B-TC.4. B-TO.4 gere la gestion operationnelle du trafic."},
{id:94,ch:1,lvl:"x",type:"qcm",q:"Le personnel d'accompagnement assure principalement la fonction de chef de bord lorsqu'il...",opts:["dirige et confie des taches aux autres membres du personnel d'accompagnement","realise des taches assignees par un autre agent","controle les titres de transport uniquement","conduit le train"],correct:[0],expOk:"Il est chef de bord quand il dirige et repartit les taches ; agent controle quand il execute les taches assignees par le chef de bord.",expNo:"Le chef de bord dirige et confie les taches ; l'agent controle execute les taches assignees."},
{id:95,ch:2,lvl:"x",type:"qcm",q:"Quel est le statut de connaissance d'un itineraire de deviation repris a l'attestation complementaire ?",opts:["il est assimile aux lignes connues (niveau equivalent)","il exige toujours un pilotage","il n'est jamais autorise","il requiert un nouvel examen a chaque usage"],correct:[0],expOk:"La connaissance des itineraires de deviation repris a l'attestation est assimilee aux lignes connues ; le conducteur peut donc assurer ce train.",expNo:"Un itineraire de deviation repris a l'attestation est assimile a une ligne connue - pas de pilotage ni d'examen requis."},
{id:96,ch:2,lvl:"x",type:"qcm",q:"Le moniteur doit completer au minimum combien de fiches d'evaluation ?",opts:["au moins une par semaine","une par mois","une par jour","une a la fin de la formation"],correct:[0],expOk:"Le moniteur complete au moins une fiche d'evaluation par semaine, renseignant progres et lacunes du candidat.",expNo:"C'est au moins une fiche par semaine."},
{id:97,ch:2,lvl:"x",type:"qrm",q:"La connaissance du materiel remorque (formation de base) inclut l'aptitude a... (plusieurs reponses)",opts:["purger ou isoler l'equipement de frein","remplacer un boyau de frein","isoler la suspension pneumatique","homologuer un nouvel engin moteur"],correct:[0,1,2],expOk:"Elle inclut : purger/isoler le frein, remplacer un boyau, desservir les freins d'immobilisation, isoler la suspension pneumatique, remedier aux fuites d'air, juger la poursuite apres anomalie MR.",expNo:"L'homologation d'un engin n'en fait pas partie. Les aptitudes visent le frein, les boyaux, la suspension, les fuites d'air, etc."},
{id:98,ch:3,lvl:"x",type:"qcm",q:"Quel livre d'ordres contient le calendrier des formations permanentes ?",opts:["le LO6","le LO5","le LO4","le LO2"],correct:[0],expOk:"Le LO6 (avis administratifs de l'encadrement du conducteur) contient le calendrier des formations permanentes et les avis du Senior Manager District.",expNo:"C'est le LO6. Le LO5 contient les avis administratifs de la direction B-TO."},
{id:99,ch:3,lvl:"x",type:"qcm",q:"En l'absence de relais et en situation INMAIN, le conducteur notifie les instructions via...",opts:["la partie D du TC612","les pages de communication du livre de bord","un D233","un M355"],correct:[0],expOk:"En INMAIN sans relais, les instructions/documents se notifient via la partie D du TC612. Dans les autres cas (ex. mise a plat), via les pages de communication du livre de bord.",expNo:"En INMAIN, c'est la partie D du TC612 ; les pages du livre de bord servent dans les autres cas (mise a plat)."},
{id:100,ch:3,lvl:"x",type:"qrm",q:"Un agent Infrabel a toujours priorite en cabine lorsqu'il transmet... (plusieurs reponses)",opts:["une IE.5 avec champ x.91 Reconnaissance meteo","une IE.6 avec champ x.91 Avarie probable a l'infrastructure","une IE.1 de perte de document","un TC612 d'INMAIN"],correct:[0,1],expOk:"L'agent Infrabel prenant part a un parcours pour une IE.5 (reconnaissance meteo) ou une IE.6 (avarie probable a l'infrastructure) a toujours priorite en cabine.",expNo:"La priorite s'applique aux parcours lies a une IE.5 (reconnaissance meteo) ou une IE.6 (avarie probable). Ni l'IE.1 ni le TC612 ne donnent cette priorite."},
{id:101,ch:3,lvl:"x",type:"qcm",q:"Sur le reseau Infrabel, a quoi correspond l'avis de securite ACPA ?",opts:["circulation avec pantographes abaisses","reduction temporaire de vitesse","raccourcissement de quai","arret exceptionnel"],correct:[0],expOk:"ACPA = avis de circulation avec pantographes abaisses. ART = reduction de vitesse, ARQ = raccourcissement de quai.",expNo:"ACPA = pantographes abaisses. ART = vitesse, ARQ = quai."},
{id:102,ch:3,lvl:"x",type:"qcm",q:"Quelle clef est remise au conducteur appele a desservir les locomotives TRAXX ?",opts:["une clef d'acces aux cabines TRAXX accompagnee d'une clef DOM","une clef LITTO","une clef WILKA G","une clef a trois branches"],correct:[0],expOk:"Le conducteur desservant les TRAXX recoit une clef d'acces a leurs cabines, accompagnee d'une clef DOM. La clef LITTO concerne l'armoire a outillage des AM/AR.",expNo:"Pour les TRAXX : clef d'acces cabine + clef DOM. La clef LITTO sert pour les AM/AR."},
{id:103,ch:3,lvl:"x",type:"qcm",q:"Le conducteur cede la conduite a un candidat-conducteur en possession d'une licence. Dans ce cas...",opts:["le conducteur qui cede la conduite en reste le responsable","le candidat devient seul responsable","une autorisation du SSICF est requise","c'est interdit"],correct:[0],expOk:"En cedant la conduite a un candidat-conducteur (licence) ou a un conducteur en etude de ligne, le conducteur qui cede en reste responsable.",expNo:"Le conducteur qui cede la conduite a un candidat en reste responsable."},
{id:104,ch:1,lvl:"x",type:"qrm",q:"Que gere HR@YourService pour les conducteurs ? (plusieurs reponses)",opts:["les primes","les mutations","les conges de circonstance","l'attribution des sillons"],correct:[0,1,2],expOk:"HR@YourService gere primes, mutations, outillage personnel, conges de circonstance, regime de travail.",expNo:"L'attribution des sillons releve d'Infrabel (I-CBE/I-O), pas de HR@YourService."},
{id:105,ch:3,lvl:"x",type:"qcm",q:"Que deviennent les donnees sauvees dans la memoire de l'appareil eDrive lors de son remplacement ?",opts:["elles sont perdues","elles sont automatiquement transferees","elles sont sauvegardees par le Helpdesk","elles restent sur le Smartlocker"],correct:[0],expOk:"Attention : toutes les donnees sauvees dans la memoire meme de l'appareil eDrive sont perdues lors du remplacement.",expNo:"Les donnees en memoire locale de l'eDrive sont perdues au remplacement - d'ou l'importance de la synchronisation."},
];

/* Fiches de synthese / memo par chapitre */
const MEMOS = [
{ch:1,titre:"Chapitre 1 - Structure des chemins de fer belges",items:[
["GI vs EF","Infrabel = gestionnaire d'infrastructure (gestion + maintenance). SNCB = entreprise ferroviaire (EF / UI), operateur historique."],
["5 Areas = districts","NW, NO, CE, SE, SO. Areas correspondent aux districts."],
["Infrabel : I-CBE vs I-O","I-CBE : surveillance securite, sillons PREVUS, ponctualite. I-O : regulation trafic, sillons IMPREVUS (realtime), catenaires, maintenance, grands projets."],
["Central Dispatch (CD)","Appui des postes de signalisation en cas de perturbation. Roles : TO (gestion temps reel), RT QO (dossiers retards), IP (diffusion infos), CDr (incidents majeurs), TPM (sillons temps reel), FSv (marchandises), RTA (analyse retards). Heberge a Bruxelles avec le RIOC."],
["Poste de signalisation","Traffic Officer (organisation generale), Safety Supervisor (coord. Safety Controllers), Traffic Supervisor (coord. Traffic Controllers), Safety Controller (mesures securite zone), Traffic Controller (regulation zone)."],
["Repartiteur courant-traction","1 par Area. Coupe l'alimentation des catenaires a la demande du Safety Controller, d'un conducteur, ou de sa propre initiative."],
["Reconnaissance terrain","Agent du mouvement : kepi bleu + gilet fluo logo Infrabel. Leader Infrabel : brassard orange logo Infrabel (SPOC). Accompagnateur/sous-chef gare B-PT : kepi/coiffe bleue logo SNCB."],
["Directions SNCB","B-TO (Transport Operations), B-CS (Customer Services), B-PT (Passenger Transport & Security), B-TC (Technics), B-ST (Stations)."],
["Conducteurs","Manoeuvre : 25 km de rayon, 60 km/h max, trains non commerciaux. Conducteur de train : trains commerciaux et non commerciaux."],
["API vs FI","API : assiste le conducteur apres un evenement choquant. FI : premieres constatations (SPAD, derive, non-respect de vitesse, circulation anormale)."],
["5 districts / 13 zones","NO : Antwerpen, Hasselt, Leuven. NW : Brugge, Gent-Oudenaarde, Kortrijk, Waasland-Dender. SO : Charleroi, Mons. SE : Arlon, Liege, Namur. CE : Bruxelles."],
["Contacts cles","Permanence conduite (gestion temps reel conducteurs), HR@YourService (primes/conges), CCT (sillons temps reel, trains de relevage), Helpdesk (depend B-TC) / Hotline (ne depend pas)."],
]},
{ch:2,titre:"Chapitre 2 - Connaissances du conducteur",items:[
["Formation","Generale : 18 jours -> licence. Specifique -> attestation complementaire. Examen final : pratique + theorique + simulateur."],
["Visites medicales","Medicale : annuelle. Approfondie : tous les 3 ans (annuelle des 55 ans). Psychotechniques : tous les 10 ans."],
["Suivi","Accompagnement >= 1x/an. Formation permanente : chaque semestre. Bilan periodique : annuel, entretien max 60 min."],
["Licence vs attestation","Licence : UE, propriete du titulaire, 10 ans. Attestation complementaire : delivree par l'UI, reste sa propriete, 3 ans, 1 par reseau/UI."],
["Categories de conduite","A1 : locos manoeuvre. A4 : autres locos manoeuvre. B1 : personnes. B2 : marchandises (limite reseau belge, wagons vides entre ateliers SNCB)."],
["Langues (rubrique 5)","F francais, N neerlandais, E anglais, D allemand. Niveau requis depuis 2016 : B1."],
["Documents administratifs","Perte licence/attestation : D233. Vol : PV de police. Port lunettes/lentilles/auditif : P1103."],
["Interruption taches critiques","Par : GI (doc + M510e), FI (doc + M510e), EF (retire attestation), SSICF (retire licence). Levee : employeur + EF + SSICF."],
["Connaissance de ligne","Evaluation : >= 60 % + pas de faute grave. Non parcouru > 10 mois : notifier M510e. Parcours dans 12 mois : prolonge ; sinon nouvelle evaluation."],
["Connaissance materiel","Formation complete (conduite, fonctionnement, depannage) ou Protection du materiel roulant. > 10 mois sans conduire : notifier M510e ; maintien = preparation + parcours sous 2 mois."],
["Pilotage","Pilote requis si pas d'attestation valable OU pas de connaissance de ligne. Le pilote a une attestation valable, connait la langue, se tient aux cotes du pilote. GI informe a chaque fois."],
["Series","Grille : colonnes = jours (R1 lundi ... R7 dimanche), lignes = services. Alternement journalier ou hebdomadaire. Hors-serie / cadre flottant : prestations au jour le jour."],
]},
{ch:3,titre:"Chapitre 3 - De la prise de service a la fin de service",items:[
["eDrive-app","Bibliotheque = Communications (nouveautes) + Documents. Instruction perso : signer D24. RID-app (marchandises dangereuses) consultable sans reseau."],
["Fascicules HLT","I Conducteur SNCB ; II signalisation laterale (A signalisation, B circulation) ; III ATP ; IV desserte engins ; V manuels/depannage ; VI frein ; VII addendum ; VIII tiers. STI : Livret de procedures."],
["Livres d'ordres","LO1 lien SEMES 2.0 ; LO2 infrastructure (PSS, deviation, fiche info, ART) ; LO3 supplements HLT ; LO4 REX + rappels ; LO5 avis B-TO ; LO6 avis encadrement (calendrier formations) ; iLO reseaux etrangers."],
["Avis de securite","ART (reduction vitesse), ACPA (pantographes abaisses), ARQ (raccourcissement quai, schema OBLIGATOIRE). Via eSEMES (integre eDrive) ou SEMES 2.0 (non integre)."],
["Infos infrastructure","PSS (schema signaux/gares/lignes), fiches de ligne (Driver-tools-app uniquement), fiches d'information (INF), fiches de deviation (1XX a 9XX selon axe)."],
["Prise de service","Demarrer eDrive, verifier synchro. Priorite : tache Debut de service (communications + SEMES non lus), icone U (autres avis urgents)."],
["Rapports","M510e (digital) / M510 (papier). M510bis = avis urgents + meteo exceptionnelle (parties A/B/C). M510 : 5 rubriques (1 incidents, 2 signaux permissifs, 3 annexes, 4 prescriptions CT, 5 personnes en cabine)."],
["Pendant le service","Calme, pas de musique, appareils employeur seulement, observer la voie, Compass PROS. eDrive en Drivemode (sinon veille) sur support/pupitre."],
["Derangement eDrive","GSM de service en remplacement. Echange via Helpdesk Mobile Devices + Smartlocker. Donnees en memoire locale PERDUES."],
["Situations exceptionnelles","API (evenement choquant), Psychologue (externe, secret pro), FI (constatations), SOC (agression/vandalisme, sinon 112), audition police (loi Salduz Plus, adresse employeur)."],
["Acces cabine","Permis TR-X01/X02 (permanents), TR-X03/X04 (temporaires, n train + date). Photo permis/licence jointe au M510e. Cabine inoccupee interdite sauf service."],
["Outillage / sac","Recu contre D24. Sac : outillage (sauf chaussures), licence + attestation(s), HLT VII.A.3 papier, 5 exemplaires IE.1-9, IN, E360, TC286 MOBI, TC612, TC431.1, M510, M510bis."],
["Codes utiles","VK.PC preparation complete ; BK.PR preparation reduite ; INMAIN maintien de service ; IDREM prise en charge INMAIN ; RES reserve ; HLP haut le pied. < arret toujours ; > arret si signal."],
]},
];
